#include <bits/stdc++.h>
using namespace std;

const int N=1100;

int n,x[N][2],y[N][2],lsx[N<<1],lsy[N<<1],s[N<<1][N<<1];
map<int,int> mpx,mpy;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d%d%d",&x[i][0],&y[i][0],&x[i][1],&y[i][1]);
        lsx[i*2-1]=x[i][0],lsx[i*2]=x[i][1];
        lsy[i*2-1]=y[i][0],lsy[i*2]=y[i][1];
    }
    sort(lsx+1,lsx+2*n+1);
    sort(lsy+1,lsy+2*n+1);
    int lenx=unique(lsx+1,lsx+2*n+1)-lsx-1,leny=unique(lsy+1,lsy+2*n+1)-lsy-1;
    for(int i=1;i<=lenx;i++)
        mpx[lsx[i]]=i;
    for(int i=1;i<=leny;i++)
        mpy[lsy[i]]=i;
    for(int i=1;i<=n;i++){
        x[i][0]=mpx[x[i][0]];
        x[i][1]=mpx[x[i][1]];
        y[i][0]=mpy[y[i][0]];
        y[i][1]=mpy[y[i][1]];
        s[x[i][0]][y[i][0]]++;
        s[x[i][0]][y[i][1]]--;
        s[x[i][1]][y[i][0]]--;
        s[x[i][1]][y[i][1]]++;
    }
    long long ans=0;
    for(int i=1;i<lenx;i++)
        for(int j=1;j<leny;j++){
            s[i][j]=s[i][j]+s[i-1][j]+s[i][j-1]-s[i-1][j-1];
            if(s[i][j])
                ans+=1LL*(lsx[i+1]-lsx[i])*(lsy[j+1]-lsy[j]);
        }
    printf("%lld",ans);
    return 0;
}
